const raw = $input.first().json || {};
let data = raw;
if (raw.query && typeof raw.query === 'object' && !Array.isArray(raw.query)) {
  data = raw.query;
} else if (typeof raw.query === 'string') {
  try { data = JSON.parse(raw.query); } catch (e) { data = raw; }
}

const scenario = String(data.scenario || raw.scenario || '').trim();
const chat_id = String(data.chat_id || raw.chat_id || '').trim();
let answers = data.answers ?? raw.answers ?? null;
if (typeof answers === 'string' && answers.trim()) {
  try { answers = JSON.parse(answers); } catch (e) {
    throw new Error('checklist: не смог разобрать answers как JSON-массив. Получено: ' + answers);
  }
}
if (!Array.isArray(answers) || answers.length === 0) answers = null;

if (!scenario) throw new Error('checklist: не передан scenario.');
if (answers && !chat_id) throw new Error('checklist: для записи ответов нужен chat_id.');

return [{ json: {
  scenario,
  chat_id,
  answers,
  answers_json: answers ? JSON.stringify(answers) : null,
  hasAnswers: !!answers
} }];

// Чеклист подгружается ДИНАМИЧЕСКИ из Google Drive (нода «Drive: скачать чеклист»).
// Источник правды: knowledge/progul_checklist.md → выгружен в Google Drive
// (fileId 1AkZ9oCM6EzNHewmEiwqvERmq9cKDMt0V). Команда правит чеклист прямо в Drive.
// Требует n8n с NODE_FUNCTION_ALLOW_EXTERNAL=adm-zip,petrovich (см. CLAUDE.md).
const AdmZip = require('adm-zip');
let checklist_content = '[чеклист не загружен из Drive]';
try {
  const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
  if (buf && buf.length) {
    if (buf[0] === 0x50 && buf[1] === 0x4B) {
      const zip = new AdmZip(buf);
      const xml = zip.readAsText('word/document.xml');
      checklist_content = xml.replace(/<\/w:p>/g, '\n').replace(/<[^>]+>/g, '').replace(/[ \t]+/g, ' ').trim();
    } else {
      checklist_content = buf.toString('utf8').replace(/^\uFEFF/, '').trim();
    }
  }
} catch (e) {
  checklist_content = '[ошибка загрузки чеклиста из Drive: ' + e.message + ']';
}

const d = $('Нормализовать вход').first().json;
// Какие документы нужны для сценария — костыль-карта (меняется редко, зашита прямо здесь).
const DOC_MAP = {
  progul_ochny: { нужен_акт: true, нужна_сз: true },
};
const docs = DOC_MAP[d.scenario] || { нужен_акт: false, нужна_сз: false };

return [{ json: { scenario: d.scenario, checklist_content, нужен_акт: docs.нужен_акт, нужна_сз: docs.нужна_сз } }];

